interface DailyFeeRevenueRow {
  total_revenue?: number | string;
}

interface DailyFeeRevenueResponse {
  data?: { rows?: DailyFeeRevenueRow[] } | DailyFeeRevenueRow[];
  rows?: DailyFeeRevenueRow[];
}

const DAILY_FEE_REVENUE_API = "/v1/broker/daily_fee_revenue";
const ONE_DAY_MS = 24 * 60 * 60 * 1000;

function getLoginContext(): LoginContext | null {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    return JSON.parse(raw) as LoginContext;
  } catch {
    return null;
  }
}

function saveProfile(p: Profile) {
  if (typeof window === "undefined") return;
  walletSetItem("orderlyProfile", JSON.stringify(p));
}

function profileFromDexStatus(
  status: NonNullable<Awaited<ReturnType<typeof fetchDexCreatorDexStatus>>>,
  current: Profile | null
): Profile {
  const hasGraduatedBrokerId = Boolean(
    status.brokerId && status.brokerId !== "demo"
  );
  const isLowCode = status.integrationType === "low_code";
  const hasFrontend = Boolean(status.repoUrl);
  return {
    ...(current || {}),
    builderName: status.brokerName || current?.builderName || "Builder",
    brokerId: status.brokerId || current?.brokerId,
    dexId: status.id || current?.dexId,
    dexConfigured: isLowCode ? hasFrontend : true,
    repoUrl: status.repoUrl || null,
    graduated: hasGraduatedBrokerId,
    adminRegistered: hasGraduatedBrokerId && status.isGraduated === true,
    pathway:
      status.integrationType === "low_code"
        ? "low-code"
        : status.integrationType === "custom"
          ? "sdk"
          : current?.pathway,
    integrationType: status.integrationType || current?.integrationType,
    createdAt: current?.createdAt || new Date().toISOString(),
  };
}

function formatCurrency(value: unknown): string {
  const n = Number(value ?? 0);
  if (!Number.isFinite(n)) return "—";
  const sign = n < 0 ? "-" : "";
  const abs = Math.abs(n);
  const format = (next: number) =>
    next.toLocaleString(undefined, {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });
  if (abs > 0 && abs < 0.01) return `${sign}< $0.01`;
  if (abs >= 1e9) return `${sign}$${format(abs / 1e9)}B`;
  if (abs >= 1e6) return `${sign}$${format(abs / 1e6)}M`;
  if (abs >= 1e3) return `${sign}$${format(abs / 1e3)}K`;
  return `${sign}$${format(abs)}`;
}

function getAnnouncementTitle(item: ApiAnnouncementItem): string {
  const message = item.message?.trim() || item.url?.trim() || "";
  if (message.length <= 70) return message;
  return `${message.slice(0, 67)}...`;
}

function formatInteger(value: unknown): string {
  if (value === undefined || value === null || value === "") return "—";
  const n = Number(value);
  if (!Number.isFinite(n)) return "—";
  return new Intl.NumberFormat(undefined, { maximumFractionDigits: 0 }).format(
    Math.floor(n)
  );
}

function firstFiniteNumber(...values: unknown[]) {
  for (const value of values) {
    const n = Number(value);
    if (Number.isFinite(n)) return n;
  }
  return undefined;
}

function getCurrentUtcDateKey() {
  return new Date().toISOString().slice(0, 10);
}

function formatDateParam(date: Date) {
  return date.toISOString().slice(0, 10);
}

function getPast30DayRevenueDateRange() {
  const now = new Date();
  const endDate = new Date(
    Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate())
  );
  const startDate = new Date(endDate.getTime() - 29 * ONE_DAY_MS);
  return {
    start_date: formatDateParam(startDate),
    end_date: formatDateParam(endDate),
  };
}

function unwrapDailyFeeRevenueRows(
  payload: DailyFeeRevenueResponse
): DailyFeeRevenueRow[] {
  if (Array.isArray(payload)) return payload;
  if (Array.isArray(payload.rows)) return payload.rows;
  if (Array.isArray(payload.data)) return payload.data;
  if (
    payload.data &&
    !Array.isArray(payload.data) &&
    Array.isArray(payload.data.rows)
  )
    return payload.data.rows;
  return [];
}

function sumPast30DayTotalRevenue(payload: DailyFeeRevenueResponse) {
  return unwrapDailyFeeRevenueRows(payload).reduce((total, row) => {
    const value = Number(row.total_revenue ?? 0);
    return Number.isFinite(value) ? total + value : total;
  }, 0);
}

async function fetchPast30DayTotalRevenue() {
  const range = getPast30DayRevenueDateRange();
  const response = await signedAdminRequest<DailyFeeRevenueResponse>({
    endpoint: `${DAILY_FEE_REVENUE_API}${buildQueryString(range)}`,
  });
  return sumPast30DayTotalRevenue(response);
}

function getCurrentUtcDailyStatsRow(
  rows: Array<{
    activeUser?: number | string;
    builderFee?: number | string;
    date?: string;
    dateString?: string;
  }>
) {
  const today = getCurrentUtcDateKey();
  return (
    rows.find(row => {
      if (typeof row.date === "string" && row.date.slice(0, 10) === today)
        return true;
      if (typeof row.dateString !== "string") return false;
      const [year, month, day] = row.dateString
        .split("-")
        .map(part => part.padStart(2, "0"));
      return [year, month, day].join("-") === today;
    }) || null
  );
}

function getLocalGreeting(): string {
  const hour = new Date().getHours();
  if (hour < 12) return "Good morning";
  if (hour < 18) return "Good afternoon";
  return "Good evening";
}

export default function HomePage() {
  const navigate = useLocalizedNavigate();
  const { t } = useTranslation();
  const [profile, setProfile] = useState<Profile | null>(null);
  const [feeModalOpen, setFeeModalOpen] = useState(false);
  const [createDexModalOpen, setCreateDexModalOpen] = useState(false);
  const [metrics, setMetrics] = useState<HomeMetrics>(emptyMetrics);
  const [announcements, setAnnouncements] = useState<ApiAnnouncementItem[]>([]);
  const [profileResolved, setProfileResolved] = useState(false);
  const [profileRedirecting, setProfileRedirecting] = useState(false);

  useEffect(() => {
    const p = getProfile();
    setProfile(p);
  }, [navigate]);

  useEffect(() => {
    let cancelled = false;

    async function resolveHomeProfile() {
      const currentProfile = getProfile();

      if (
        currentProfile?.role === "ambassador" ||
        currentProfile?.role === "broker"
      ) {
        if (!cancelled) {
          setProfile(currentProfile);
          setProfileResolved(true);
          setProfileRedirecting(true);
          navigate("/distributor-dashboard", { replace: true });
        }
        return;
      }

      const walletAddress =
        getLoginContext()?.walletAddress || currentProfile?.walletAddress;
      if (walletAddress) {
        const ambassadorAccount = await fetchAmbassadorAccount(walletAddress);
        if (cancelled) return;
        if (ambassadorAccount?.account_id) {
          const nextProfile: Profile = {
            accountId: ambassadorAccount.account_id,
            builderName: "Ambassador distributor",
            brokerId: "ambassador",
            role: "ambassador",
            walletAddress,
            createdAt: currentProfile?.createdAt || new Date().toISOString(),
          };
          saveProfile(nextProfile);
          setProfile(nextProfile);
          setProfileResolved(true);
          setProfileRedirecting(true);
          window.dispatchEvent(new CustomEvent("authChanged"));
          navigate("/distributor-dashboard", { replace: true });
          return;
        }
      }

      try {
        const status = await fetchDexCreatorDexStatus();
        if (cancelled) return;
        if (status && status.exists !== false) {
          const nextProfile = profileFromDexStatus(status, currentProfile);
          saveProfile(nextProfile);
          if (status.id) walletSetItem("orderlyDexId", status.id);
          setProfile(nextProfile);
          setProfileResolved(true);
          window.dispatchEvent(new CustomEvent("profileUpdated"));
          return;
        }
      } catch {
        // Fall back to local profile state when dex-creator is unavailable.
      }

      if (cancelled) return;
      if (!currentProfile?.builderName) {
        setProfileRedirecting(true);
        navigate("/onboarding", { replace: true });
        return;
      }
      setProfile(currentProfile);
      setProfileResolved(true);
    }

    void resolveHomeProfile().catch(() => {
      if (cancelled) return;
      const currentProfile = getProfile();
      if (currentProfile?.builderName) {
        setProfile(currentProfile);
        setProfileResolved(true);
      } else {
        setProfileRedirecting(true);
        navigate("/onboarding", { replace: true });
      }
    });

    return () => {
      cancelled = true;
    };
  }, [navigate]);

  useEffect(() => {
    function syncProfile() {
      setProfile(getProfile());
    }

    window.addEventListener("authChanged", syncProfile);
    window.addEventListener("storage", syncProfile);
    return () => {
      window.removeEventListener("authChanged", syncProfile);
      window.removeEventListener("storage", syncProfile);
    };
  }, []);

  useEffect(() => {
    if (
      !profileResolved ||
      profile?.role === "ambassador" ||
      profile?.role === "broker"
    )
      return;
    let cancelled = false;

    fetchDexCreatorDexStatus()
      .then(status => {
        if (cancelled || !status || status.exists === false) return;
        const p = getProfile();
        if (!p) return;

        const nextProfile = profileFromDexStatus(status, p);

        saveProfile(nextProfile);
        if (status.id) walletSetItem("orderlyDexId", status.id);
        setProfile(nextProfile);
        window.dispatchEvent(new CustomEvent("profileUpdated"));
      })
      .catch(() => {
        // Keep local state when the dex-creator API is unavailable in this environment.
      });

    return () => {
      cancelled = true;
    };
  }, [profileResolved, profile?.role]);

  const isGraduated = !!profile?.graduated;
  const isDistributor =
    profile?.role === "ambassador" || profile?.role === "broker";

  useEffect(() => {
    let cancelled = false;

    fetchPublicAnnouncements()
      .then(rows => {
        if (cancelled) return;
        setAnnouncements(
          rows.filter(row => row.message?.trim() || row.url?.trim()).slice(0, 3)
        );
      })
      .catch(() => {
        if (!cancelled) setAnnouncements([]);
      });

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    const brokerId = profile?.brokerId;
    if (!brokerId || brokerId === "demo" || isDistributor || !isGraduated) {
      setMetrics(emptyMetrics);
      return;
    }

    let cancelled = false;

    const loadMetrics = () => {
      setMetrics(current => {
        const hasLoadedValue = [
          current.volume24hValue,
          current.fees30dValue,
          current.tvlValue,
          current.activeUsersValue,
          current.connectedUsersValue,
        ].some(value => Number.isFinite(value));
        return {
          ...current,
          loading: !hasLoadedValue,
          refreshing: hasLoadedValue,
        };
      });

      Promise.allSettled([
        fetchPublicVolumeStats(brokerId),
        fetchPublicBalanceStats({ broker_id: brokerId }),
        fetchBuilderDailyStats({ broker_id: brokerId }),
        fetchPublicBrokerStats({ broker_id: brokerId }),
        fetchPast30DayTotalRevenue(),
      ])
        .then(
          ([
            volumeResult,
            balanceResult,
            dailyStatsResult,
            brokerStatsResult,
            revenue30dResult,
          ]) => {
            if (cancelled) return;
            const volumeStats =
              volumeResult.status === "fulfilled" ? volumeResult.value : null;
            const balance =
              balanceResult.status === "fulfilled" ? balanceResult.value : null;
            const dailyStats =
              dailyStatsResult.status === "fulfilled"
                ? dailyStatsResult.value
                : null;
            const currentDailyStats = dailyStats
              ? getCurrentUtcDailyStatsRow(dailyStats)
              : null;
            const brokerStats =
              brokerStatsResult.status === "fulfilled"
                ? brokerStatsResult.value
                : [];
            const fees30dValue =
              revenue30dResult.status === "fulfilled"
                ? revenue30dResult.value
                : undefined;
            const volume24hValue = volumeStats?.perp_volume_last_1_day;
            const tvlValue = balance?.total_holding;
            const activeUsersValue = Number(currentDailyStats?.activeUser ?? 0);
            const connectedUsersValue = firstFiniteNumber(
              ...brokerStats.map(row => row.connected_user)
            );
            setMetrics({
              volume24h: volumeStats ? formatCurrency(volume24hValue) : "—",
              volume24hValue: Number(volume24hValue),
              tvl: balance ? formatCurrency(tvlValue) : "—",
              tvlValue: Number(tvlValue),
              activeUsers: formatInteger(activeUsersValue),
              activeUsersValue,
              connectedUsers:
                brokerStatsResult.status === "fulfilled"
                  ? formatInteger(connectedUsersValue)
                  : "—",
              connectedUsersValue,
              fees30d:
                revenue30dResult.status === "fulfilled"
                  ? formatCurrency(fees30dValue)
                  : "—",
              fees30dValue: Number(fees30dValue),
              loading: false,
              refreshing: false,
            });
          }
        )
        .catch(() => {
          if (!cancelled)
            setMetrics(current => ({
              ...current,
              loading: false,
              refreshing: false,
            }));
        });
    };

    loadMetrics();
    const intervalId = window.setInterval(loadMetrics, 30000);

    return () => {
      cancelled = true;
      window.clearInterval(intervalId);
    };
  }, [profile?.brokerId, isDistributor, isGraduated]);

  if (!profileResolved) {
    return (
      <PageShell pageTitle={t("home.title")}>
        <div className="flex min-h-[400px] flex-col items-center justify-center gap-3">
          <div className="inline-block h-8 w-8 animate-spin rounded-full border-2 border-(--line-subtle) border-t-(--fg-brand)" />
          {profileRedirecting && (
            <div className="text-sm font-medium text-(--fg-secondary)">
              Redirecting...
            </div>
          )}
        </div>
      </PageShell>
    );
  }

  const tasks = profile
    ? buildTasks(profile, {
        dexFrontendTitle: t("home.onboarding.task.dexFrontend.title"),
      })
    : [];

  return (
    <PageShell pageTitle={t("home.title")}>
      {isDistributor ? (
        <DistributorHome profile={profile} setFeeModalOpen={setFeeModalOpen} />
      ) : !isGraduated || profile?.adminRegistered !== true ? (
        <OnboardingHome
          tasks={tasks}
          onCreateDex={() => setCreateDexModalOpen(true)}
        />
      ) : (
        <BuilderHome
          profile={profile}
          metrics={metrics}
          announcements={announcements}
        />
      )}

      <FeeTierModal
        open={feeModalOpen}
        onClose={() => setFeeModalOpen(false)}
      />
      <CreateDexFrontendModal
        open={createDexModalOpen}
        profile={profile}
        onClose={() => setCreateDexModalOpen(false)}
        onProfileUpdated={setProfile}
      />
    </PageShell>
  );
}

