function AnimatedMetricValue({
  value,
  fallback,
  formatValue,
}: {
  value?: number;
  fallback: string;
  formatValue?: (value: number) => string;
}) {
  const [displayValue, setDisplayValue] = useState(0);
  const previousTargetRef = useRef(0);

  useEffect(() => {
    if (!formatValue || !Number.isFinite(value)) return;

    const target = Number(value);
    const from = previousTargetRef.current;
    const startedAt = performance.now();
    const duration = 900;
    let frame = 0;

    const tick = (now: number) => {
      const elapsed = Math.min((now - startedAt) / duration, 1);
      const accelerated = elapsed * elapsed * elapsed;
      setDisplayValue(from + (target - from) * accelerated);

      if (elapsed < 1) {
        frame = requestAnimationFrame(tick);
      } else {
        previousTargetRef.current = target;
        setDisplayValue(target);
      }
    };

    frame = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frame);
  }, [formatValue, value]);

  if (!formatValue || !Number.isFinite(value)) return <>{fallback}</>;
  return <>{formatValue(displayValue)}</>;
}

