function CreateDexFrontendModal({
  open,
  profile,
  onClose,
  onProfileUpdated,
}: {
  open: boolean;
  profile: Profile | null;
  onClose: () => void;
  onProfileUpdated: (profile: Profile) => void;
}) {
  const [creationState, setCreationState] =
    useState<DexFrontendCreationState>("idle");
  const [errorMessage, setErrorMessage] = useState("");
  const isCreating = creationState === "creating";

  useEffect(() => {
    if (!open) return;
    setCreationState("idle");
    setErrorMessage("");
  }, [open]);

  async function handleCreateFrontend() {
    const currentProfile = getProfile() || profile;
    if (!currentProfile?.dexId) {
      setCreationState("error");
      setErrorMessage("Builder profile is not ready. Refresh and try again.");
      return;
    }

    setCreationState("creating");
    setErrorMessage("");

    try {
      const formData = new FormData();
      if (currentProfile.builderName) {
        formData.append("brokerName", currentProfile.builderName);
      }

      const result = await createDexCreatorFrontend(
        currentProfile.dexId,
        formData
      );
      const nextProfile: Profile = {
        ...profileFromDexStatus(result, currentProfile),
        dexConfigured: true,
        repoUrl: result.repoUrl || null,
        pathway: "low-code",
        integrationType: result.integrationType || "low_code",
      };

      saveProfile(nextProfile);
      if (result.id) walletSetItem("orderlyDexId", result.id);
      onProfileUpdated(nextProfile);
      window.dispatchEvent(new CustomEvent("profileUpdated"));
      setCreationState("success");
    } catch (err) {
      setCreationState("error");
      setErrorMessage(
        err instanceof Error ? err.message : "Failed to create DEX"
      );
    }
  }

  function handleClose() {
    if (isCreating) return;
    onClose();
  }

  return (
    <Modal
      open={open}
      onClose={handleClose}
      title="Create your DEX frontend"
      showCloseButton={!isCreating}
    >
      {creationState === "success" ? (
        <div className="space-y-5">
          <div className="flex flex-col items-center gap-4 py-4 text-center">
            <div className="flex h-16 w-16 items-center justify-center rounded-full bg-[var(--bg-positive-subtle)] text-[var(--fg-positive)]">
              <Rocket className="h-8 w-8" />
            </div>
            <div>
              <h3 className="text-lg font-medium text-[var(--fg-base)]">
                DEX frontend created
              </h3>
              <p className="mt-1 text-sm text-[var(--fg-secondary)]">
                Your hosted DEX frontend is ready. You can further customize
                settings if needed.
              </p>
            </div>
          </div>
          <div className="flex justify-end">
            <button
              type="button"
              onClick={onClose}
              className="inline-flex h-10 items-center justify-center rounded-full px-5 text-sm font-medium text-[var(--fg-base)] transition-opacity hover:opacity-90"
              style={{ background: "var(--bg-primary)" }}
            >
              Back to setup
            </button>
          </div>
        </div>
      ) : (
        <div className="space-y-5">
          <p className="text-sm leading-5 text-[var(--fg-secondary)]">
            This will create a hosted DEX frontend with our no-code tools. You
            can customize branding, themes, and settings after creation.
          </p>

          <div className="rounded-xl border border-[var(--border-subtle)] bg-[var(--bg-surface-secondary)] p-5">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-[var(--bg-primary-subtle)] text-[var(--fg-brand)]">
                <Rocket className="h-5 w-5" />
              </div>
              <div>
                <h3 className="text-base font-medium text-[var(--fg-base)]">
                  {profile?.builderName || "Your DEX"}
                </h3>
                <p className="text-sm text-[var(--fg-secondary)]">
                  Hosted on GitHub Pages with automatic deployments
                </p>
              </div>
            </div>
          </div>

          {creationState === "error" && (
            <div className="rounded-lg border border-[var(--border-negative)] bg-[var(--bg-negative-subtle)] p-3 text-sm text-[var(--fg-negative)]">
              {errorMessage}
            </div>
          )}

          <div className="flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
            {!isCreating && (
              <button
                type="button"
                onClick={handleClose}
                className="inline-flex h-10 items-center justify-center rounded-full border border-[var(--border-subtle)] px-4 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
              >
                Cancel
              </button>
            )}
            <button
              type="button"
              disabled={isCreating}
              onClick={() => void handleCreateFrontend()}
              className="inline-flex h-10 items-center justify-center gap-2 rounded-full px-5 text-sm font-medium text-[var(--fg-base)] transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
              style={{ background: "var(--bg-primary)" }}
            >
              {isCreating ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Creating frontend...
                </>
              ) : (
                <>
                  <Rocket className="h-4 w-4" />
                  Create
                </>
              )}
            </button>
          </div>
        </div>
      )}
    </Modal>
  );
}

