function buildTasks(profile: Profile, copy: { dexFrontendTitle: string }) {
  const tasks: {
    id: string;
    action: string;
    title: string;
    desc: string;
    done: boolean;
    blocked?: boolean;
    optional?: boolean;
    href?: string;
  }[] = [];

  const hasDexFrontend =
    Boolean(profile.repoUrl) ||
    (profile.pathway === "low-code" && Boolean(profile.dexConfigured));

  tasks.push({
    id: "dexConfigured",
    action: hasDexFrontend ? "Configure" : "Create",
    title: copy.dexFrontendTitle,
    desc: hasDexFrontend
      ? "Configure and customize your hosted DEX frontend, including branding, deployment, domains, and settings."
      : "Optional: Create a hosted DEX frontend with our no-code tools. You can skip this and use the SDK directly.",
    done: hasDexFrontend,
    optional: true,
    href: "/frontend-setup",
  });
  tasks.push({
    id: "graduated",
    action: "Graduate",
    title: "Graduation",
    desc: "Choose your broker ID, configure default trading fees and make fee payment to unlock full broker capabilities.",
    done: !!profile.graduated,
    href: "/graduation",
  });
  tasks.push({
    id: "adminRegistered",
    action: "Set up",
    title: "Admin account",
    desc: "Set up your admin account using your EOA wallet or Gnosis multisig.",
    done: !!profile.adminRegistered,
    blocked: !profile.graduated,
    href: "/admin-setup",
  });

  return tasks;
}
